from dataclasses import dataclass
from enum import Enum
from typing import Optional


class ReviewSeverity(Enum):
    BLOCKING  = "blocking"    # must resolve before design sign-off
    ADVISORY  = "advisory"    # recommended; non-blocking for sign-off


@dataclass
class CheckItem:
    dimension: str
    check_id: str
    description: str
    severity: ReviewSeverity
    passed: Optional[bool] = None    # None = not yet reviewed
    reviewer_note: str = ""

    @property
    def is_blocking_failure(self) -> bool:
        return self.severity == ReviewSeverity.BLOCKING and self.passed is False


@dataclass
class TransparencyChecks:
    ai_label_on_all_surfaces: CheckItem
    confidence_communicated: CheckItem
    source_attribution_present: CheckItem
    session_context_disclosed: CheckItem
    ai_disclaimer_present: CheckItem

    def blocking_failures(self) -> list[CheckItem]:
        return [c for c in vars(self).values() if c.is_blocking_failure]

    def is_approved(self) -> bool:
        return len(self.blocking_failures()) == 0

@dataclass
class ErrorHandlingChecks:
    timeout_state_designed: CheckItem
    guardrail_block_explained: CheckItem
    refusal_is_helpful: CheckItem
    low_confidence_ui_distinct: CheckItem
    slot_failure_fallback_designed: CheckItem
    model_unavailable_graceful: CheckItem

    def all_checks(self) -> list[CheckItem]:
        return list(vars(self).values())

    def blocking_failures(self) -> list[CheckItem]:
        return [c for c in self.all_checks() if c.is_blocking_failure]

@dataclass
class ControlChecks:
    correction_possible: CheckItem
    undo_for_irreversible: CheckItem
    human_override_explicit: CheckItem
    feedback_mechanism: CheckItem
    session_restart_accessible: CheckItem

    def blocking_failures(self) -> list[CheckItem]:
        return [c for c in vars(self).values() if c.is_blocking_failure]

from dataclasses import dataclass, field


@dataclass
class GenAIDesignReview:
    review_id: str
    flow_id: str
    reviewer: str
    reviewed_at: str   # ISO-8601
    transparency: TransparencyChecks
    error_handling: ErrorHandlingChecks
    control: ControlChecks

    # safety and latency checks follow the same pattern
    all_blocking_failures: list[CheckItem] = field(default_factory=list)

    def __post_init__(self) -> None:
        self.all_blocking_failures = (
            self.transparency.blocking_failures()
            + self.error_handling.blocking_failures()
            + self.control.blocking_failures()
            # + safety.blocking_failures() + latency.blocking_failures()
            # + scope.blocking_failures()
        )

    @property
    def is_approved(self) -> bool:
        return len(self.all_blocking_failures) == 0

    def blocking_summary(self) -> list[str]:
        return [
            f"[{c.dimension}] {c.check_id}: {c.description}"
            for c in self.all_blocking_failures
        ]

    def sign_off_status(self) -> str:
        if self.is_approved:
            return f"APPROVED by {self.reviewer} at {self.reviewed_at}"
        return (
            f"BLOCKED — {len(self.all_blocking_failures)} blocking issue(s): "
            + "; ".join(c.check_id for c in self.all_blocking_failures)
        )

from dataclasses import dataclass
from typing import Optional


@dataclass
class PersonaDesignCheck:
    persona_id: str
    ai_literacy: str      # "low" | "medium" | "high"
    primary_language: str
    is_vulnerable: bool

    def required_extra_checks(self) -> list[str]:
        checks = []
        if self.ai_literacy == "low":
            checks.append("First-time user onboarding: explain what AI can and cannot do")
            checks.append("Avoid jargon in all AI-facing copy (no 'hallucination', 'model', 'prompt')")
            checks.append("Provide example queries at entry to reduce blank-screen paralysis")
        if self.is_vulnerable:
            checks.append("Distress path must be visible without scrolling")
            checks.append("No animated content that could trigger photosensitivity")
            checks.append("Crisis resource link in footer of all AI responses (if applicable)")
        if self.primary_language != "en":
            checks.append("Refusal and error messages are translated — not English only")
            checks.append("RTL layout verified if applicable")
        return checks


def run_persona_checks(
    review: "GenAIDesignReview",
    personas: list[PersonaDesignCheck],
) -> dict[str, list[str]]:
    """Returns dict of persona_id → list of extra checks that must pass."""
    return {p.persona_id: p.required_extra_checks() for p in personas}
